INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "A", 44, 8, 2, 27, "こんにちは！　ヒヨリでっす！\n困っている人がいたら助けにいくよ！\nよかったら一緒に来ない？", "トゥインクルウィッシュ", 155, "人助け、応援", 100101, 16, "東山奈央", "人助けが大好き！　前向き格闘娘", "獣人族", "ヒヨリ");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "O", 47, 4, 2, 5, "あんまり役に立てるかはわからないけど…\nわたしも頑張って、\nみんなをサポートするね！", "トゥインクルウィッシュ", 158, "料理、人間観察", 100201, 17, "種田梨沙", "戦闘のサポートが得意な、心優しい少女", "ヒューマン", "ユイ");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "B", 46, 1, 2, 12, "キミと会ったのもきっと何かの縁だ\n一緒に塔の頂上を目指す仲間として\n頑張っていこう。よろしく頼む", "トゥインクルウィッシュ", 163, "読書、乗馬、お茶", 100301, 18, "早見沙織", "クールで何事にも真っ直ぐな剣士", "魔族", "レイ");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "O", 27, 8, 5, 10, "イタズラなら任せて！\nにいちゃん、引っかからないように気を付けなよー♪", "リトルリリカル", 128, "いたずら、探検", 100401, 9, "諸星すみれ", "探検好きのイタズラっ子", "ヒューマン", "ミソギ");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "O", 40, 11, 8, 25, "？？？", "王宮騎士団（NIGHTMARE）", 146, "ヒーローごっこ", 100501, 12, "下田麻美", "ヒーローに憧れる騎士見習いの少女", "獣人族", "マツリ");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "O", 42, 11, 7, 22, "アカリ、まだわからないことが多くて…\nだからこれから\nいろいろ教えてくださいね、お兄ちゃん！", "悪魔偽王国軍（ディアボロス）", 150, "サックス", 100601, 13, "浅倉杏美", "甘え上手なみんなの人気者", "魔族", "アカリ");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "B", 32, 1, 7, 23, "難しいことはわからないの～\nただ毎日プリンを食べられるなら、\n幽霊のままでいいの～", "悪魔偽王国軍（ディアボロス）", 130, "プリンを食べること", 100701, 14, "雨宮天", "プリン大好きゴースト娘", "魔族", "ミヤコ");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "AB", 40, 10, 15, 10, "ボクって本当に美しいなあ…\n可愛くて美しいなんて本当に罪だと思うけど\n生まれもったものだから仕方ないんだ♪", "ヴァイスフリューゲル　ランドソル支部", 150, "鏡で自分を見ること", 100801, 14, "大空直美", "ボクは誰よりも美しい", "エルフ", "ユキ");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "A", 45, 7, 13, 5, "いいか、絶対に私を真名で呼ぶなよ？\n常に「機関」の眼や耳の存在を疑え\nそれが、生きのびるための術だ…！", "トワイライトキャラバン", 159, "小説執筆", 100901, 17, "髙野麻美", "前世を信じる中二病患者、「疾風の冥姫」", "魔族", "アンナ");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "O", 42, 9, 10, 22, "マホマホ王国のお姫はんの、マホ姫どす！\nけったいな顔してどないしはったん？\nマホマホ王国はずーっと遠くの国なんどす？", "自警団（カォン）", 155, "空想、ぬいぐるみ集め", 101001, 16, "内田真礼", "マホマホ王国のプリンセス", "獣人族", "マホ");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "A", 44, 8, 3, 25, "覚えていないと思うんですけど…\n私は妹なんですよ！\nだからお兄ちゃんって呼んでいいですか？", "ラビリンス", 156, "お裁縫", 101101, 15, "阿澄佳奈", "人懐っこくてマシンガントークな妹系少女", "ヒューマン", "リノ");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "A", 46, 12, 6, 24, "私はハツネ！　困っている人の味方だよ！\n困った時は、いつでも言ってね♪\n私のちょ…ま、魔法で助けてあげるから！", "フォレスティエ", 156, "妹と遊ぶこと、二度寝、昼寝、早寝", 101201, 17, "大橋彩香", "みんなのために超能力を使う眠り姫", "エルフ", "ハツネ");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "O", 55, 8, 13, 21, "", "トワイライトキャラバン", 166, "読書、魔法", 101301, 18, "佳村はるか", "オタク全開な魔法少女", "魔族", "ナナカ");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "AB", 41, 11, 10, 3, "test", "自警団（カォン）", 152, "読書、推理", 101401, 15, "水瀬いのり", "頭脳明晰な美少女名探偵", "獣人族", "カスミ");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "O", 54, 9, 6, 5, "test", "フォレスティエ", 165, "絵本作り", 101501, 21, "國府田マリ子", "母性溢れる優しいみんなの「ミサト先生」", "エルフ", "ミサト");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "O", 48, 4, 14, 10, "ヒデサイ、ちょっす～！　うち、漢字と計算は\nちょっち…てか、おに苦手なんだ～\nでもでも、ファッションだったら任せて～！", "ルーセント学院", 167, "ファッション", 101601, 17, "上坂すみれ", "天真爛漫で人気者のカリスマモデル", "魔族", "スズナ");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "A", 53, 7, 10, 7, "ハイターイ！　歌って踊って、\n最高に盛り上がるさ～！\nやさやさ、キミも一緒に踊るさ～！", "自警団（カォン）", 158, "踊り、空手", 101701, 17, "高森奈津美", "いつでも「なんくるないさ～」な天然娘", "獣人族", "カオリ");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "B", 52, 8, 14, 14, "いつも助けてくれてありがとう\n私のほうが年上なのに\n頼ってばかりでごめんなさい～", "ルーセント学院", 162, "恋愛小説、恋愛舞台、恋愛漫画の鑑賞", 101801, 23, "伊藤静", "多くの男性を魅了する無垢な女教師", "魔族", "イオ");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "O", 21, 4, 5, 3, "ぴょんぴょん、うさぎさんになりたいな～♪　\nミミ、うさぎさんになれたら、\n最初におにいちゃんに見せてあげるね！", "リトルリリカル", 117, "かわいいもの集め", 102001, 10, "日高里菜", "お歌もにんじんも、ウサギさんも大好き♪", "獣人族", "ミミ");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "B", 40, 6, 9, 9, "あの、えっと…私、く、クルミですぅ…\nふ、ふぇぇぇ…ど、どうしようぅ…\nは、恥かしくて…ご、ごめんなさいぃぃ！", "サレンディア救護院", 150, "観劇、おままごと", 102101, 12, "植田佳奈", "泣き虫で臆病な守ってあげたい女の子", "ヒューマン", "クルミ");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "O", 40, 11, 7, 22, "え、えっと…こ、こういうときって、\nどういうことを言えばいいんだっけ…\nうう、どうしてちゃんと喋れないの…", "悪魔偽王国軍（ディアボロス）", 150, "ゲーム全般", 102201, 13, "原紗友里", "人見知りであまのじゃくな女の子", "魔族", "ヨリ");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "B", 38, 5, 9, 10, "この子はね、ぷうきちって言うんだ\n武器なんだけど、しゃべるんだよ♪\n大事な大事な、私の友達なんだぁ～！", "サレンディア救護院", 148, "屋内でできる遊び", 102301, 14, "芹澤優", "ぷうきちといつも一緒！", "ヒューマン", "アヤネ");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "O", 43, 12, 9, 12, "うぅ…ごめんなさい～…\nまたキッチンを爆発させてしまいました～\nこれじゃあメイド失格です…", "サレンディア救護院", 154, "ご奉仕", 102501, 15, "悠木碧", "お嬢さまのためにがんばるドジっ娘メイド", "ヒューマン", "スズメ");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "B", 42, 1, 11, 1, "test", "牧場（エリザベスパーク）", 144, "あんパン", 102601, 17, "小岩井ことり", "遊びと睡眠が何より大事なぐうたら娘", "獣人族", "リン");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "B", 43, 7, 13, 30, "『壊し屋』の二つ名を持つ私…\nですが、怖がる必要はありませんわ\nあなた様は大切な運命の人ですから…", "トワイライトキャラバン", 154, "実験、裁縫、料理", 102701, 16, "橋本ちなみ", "運命の相手に一途すぎる乙女", "魔族", "エリコ");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "A", 43, 10, 9, 4, "貧乏性？　いいえ、\n「もったいない」の精神で\n日々を過ごしてるだけよ！", "サレンディア救護院", 156, "経営、お茶会", 102801, 17, "堀江由衣", "救護院を経営する優しい庶民派お嬢様", "エルフ", "サレン");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "B", 40, 1, 4, 24, "いつか世界中の人達をファンにしてみせる！\nトップアイドルになるその日まで、\n応援よろしくね♪", "カルミナ", 157, "舞台鑑賞、ダンス", 102901, 17, "日笠陽子", "歌って踊れる大人気アイドル", "ヒューマン", "ノゾミ");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "O", 51, 8, 15, 31, "スシ、ゲイシャ、テンプラ…\nはふぅ～！\nトーゴクの文化はステキデスね～！", "ヴァイスフリューゲル　ランドソル支部", 163, "忍法開発", 103001, 16, "佐藤聡美", "トーゴクの神秘、オシエテクダサイ！", "ヒューマン", "ニノン");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "AB", 42, 12, 7, 22, "私、小さい頃から人には見えないものが\n見えていたんです。今もあなたの後ろに\n一人、二人、三人…賑やかですね", "悪魔偽王国軍（ディアボロス）", 157, "占い", 103101, 18, "大坪由佳", "占いが得意な霊能少女", "魔族", "シノブ");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "AB", 45, 3, 12, 12, "この私とともにいる限り、\nお金に不自由はさせませんわ！", "メルクリウス財団", 157, "慈善事業", 103201, 18, "松嵜麗", "一人前の商人を目指すパワフルお嬢様", "ヒューマン", "アキノ");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "B", 35, 3, 11, 3, "オラはどんな時でもみんなに笑顔を届ける\n最高の芸人目指してる！\n一緒に頑張るべ！", "牧場（エリザベスパーク）", 142, "漫才", 103301, 20, "新田恵海", "みんなを笑顔にするお笑い牧場主", "ヒューマン", "マヒル");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "A", 55, 3, 12, 16, "キミには情けないところばかり\n見られているけど、こんなところ、\nキミ以外には見せないんだからね？", "メルクリウス財団", 164, "ウインドーショッピング", 103401, 22, "今井麻美", "純情でほっとけない大人の女性", "エルフ", "ユカリ");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "A", 21, 2, 5, 2, "test", "リトルリリカル", 118, "お勉強", 103601, 8, "小倉唯", "礼儀正しくしっかり者のちびっ子優等生", "エルフ", "キョウカ");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "A", 43, 8, 8, 11, "test", "王宮騎士団（NIGHTMARE）", 149, "剣術、年長者をからかう", 103701, 13, "茅原実里", "義理堅くてからかい好きな剣術少女", "ヒューマン", "トモ");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "A", 40, 11, 11, 3, "ゴホッ、ゴホッ…か、身体は弱いけど、\nせめて気持ちだけでも前向きに…！\nあっ、でもダメ…立ちくらみが…", "牧場（エリザベスパーク）", 153, "読書、お散歩", 103801, 14, "小清水亜美", "読書が趣味の病弱少女", "獣人族", "シオリ");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "AB", 44, 6, 6, 6, "友達ができるその日まで…\nBB団で\nトレーニングですっ！", "フォレスティエ", 158, "友達作りのイメトレ", 104001, 13, "花澤香菜", "「友達」に憧れる、エルフの森の女の子", "エルフ", "アオイ");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "O", 46, 6, 4, 3, "私は人々の平和を守るため、唱喚術を使って\n戦います。…最近は、ア、アイドルとしても\n活動してますが、そちらはまだ不慣れで…", "カルミナ", 163, "各種楽器", 104201, 17, "福原綾香", "人々を守るために歌う、唱喚士の少女", "ヒューマン", "チカ");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "O", 54, 8, 10, 9, "腹へってたら言えよな\n簡単でよければ\nすっげー旨いもん食わせてやるよ！", "自警団（カォン）", 168, "お菓子作り", 104301, 17, "小松未可子", "男勝りで情に厚いワイルド娘", "獣人族", "マコト");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "A", 50, 5, 7, 5, "test", "悪魔偽王国軍（ディアボロス）", 172, "世界征服", 104401, "??", "丹下桜", "かつては夜を支配した最強の吸血鬼", "魔族", "イリヤ");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "AB", 49, 11, 15, 19, "あなたのことを考えていました\n…逆らえないクウカをああして、こうして\nぐふ、ぐふふふ…", "ヴァイスフリューゲル　ランドソル支部", 157, "小説を読むこと", 104501, 18, "長妻樹里", "妄想大好き！　ほんとは照れ屋な女の子", "ヒューマン", "クウカ");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "AB", 48, 3, 12, 1, "お金もうけの話なら、ぜひともあたしに\n持ってくるにゃ！　稼げるなら１ルピだって\n見逃さないのが、あたしの信条にゃ～♪", "メルクリウス財団", 158, "猫とたわむれること", 104601, 19, "沼倉愛美", "弱きを助け強きをくじく猫娘", "獣人族", "タマキ");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "A", 50, 10, 8, 25, "？？？", "王宮騎士団（NIGHTMARE）", 171, "格闘技、湯浴み", 104701, 25, "川澄綾子", "素顔を見せない冷静沈着な女性騎士", "ヒューマン", "ジュン");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "O", 49, 11, 12, 11, "私がキミの師匠になってあげる！\nもちろんタダとはいかないわ\n時給はしっかりもらうから", "メルクリウス財団", 163, "傭兵などのアルバイト", 104801, 20, "田所あずさ", "仕事も私事も効率優先な傭兵少女", "ヒューマン", "ミフユ");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "O", 54, 10, 3, 24, "身の回りのお世話はお姉ちゃんがやってあげるね！\nお料理も、お洗濯も、お掃除も\nお風呂で背中も流してあげちゃうぞっ！", "ラビリンス", 168, "家事全般", 104901, 18, "生天目仁美", "お姉ちゃんがお世話してあげるからねっ！", "ヒューマン", "シズル");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "A", 22, 1, 14, 3, "アタシのこと呼んだ？\nレディの魅力で夢中にさせてあげるわね！", "ルーセント学院", 120, "ファッション誌鑑賞、コスメ集め", 105001, 11, "久野美咲", "ちょっとおませな恋に恋する女の子", "魔族", "ミサキ");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "A", 53, 3, 13, 7, "私は科学者だけど、\n医者の真似事もしてるの\n病気になったら診てあげるわ", "トワイライトキャラバン", 166, "研究、実験", 105101, 27, "三石琴乃", "実験が趣味の危険な科学者", "ヒューマン", "ミツキ");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "A", 100, 3, 11, 14, "私、ごく普通の、どこにでもいる女の子よ！\nみ、見た目以外はね…", "牧場（エリザベスパーク）", 150, "毛繕い、お喋り", 105201, 17, "徳井青空", "乙女チックなもふもふアニマル", "獣人族", "リマ");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "A", 33, 7, 15, 28, "「白き翼」こと、ヴァイスフリューゲル…\nその名に恥じぬよう、天高く舞い、\n華麗に敵を倒してみせる！", "ヴァイスフリューゲル　ランドソル支部", 140, "お菓子屋通い", 105301, 17, "辻あゆみ", "見た目も中身もお子ちゃまな異国の軍人", "ヒューマン", "モニカ");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "AB", 45, 9, 4, 7, "test", "カルミナ", 153, "裁縫", 105401, 14, "木戸衣吹", "ファッション大好きなキュートガール", "ヒューマン", "ツムギ");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "O", 43, 4, 15, 7, "test", "ヴァイスフリューゲル　ランドソル支部", 155, "観察", 105501, 16, "大関英里", "どこまでも一途に慕う、純情乙女", "エルフ", "アユミ");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "B", 54, 7, 13, 11, "test", "トワイライトキャラバン", 167, "釣り", 105601, 25, "佐藤利奈", "人情味溢れる粋でいなせな「姉御」", "ヒューマン", "ルカ");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "O", 45, 3, "", 10, "私ね、一人前の騎空士になりたいんだ\nいつか父さんみたいな騎空士になって、\n空の果てまで旅する。それが私の夢だよ！", "？？？", 156, "冒険、おしゃべり", 105701, 17, "金元寿子", "空への冒険を夢見る騎空士の少女", "ヒューマン", "ジータ");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "O", 46, 3, 1, 31, "あ、あの…何か食べ物持っていませんか？\nもう、お腹ペコペコで…", "美食殿", 156, "食べ歩き、料理", 105801, 17, "M・A・O", "いつも元気な腹ペコ少女", "ヒューマン", "ペコリーヌ");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "B", 35, 5, 1, 11, "主さまのガイド役を仰せつかりました\nわたくし、主さまに満足していただけるよう\n誠心誠意尽くさせていただきます", "美食殿", 140, "瞑想、動植物の飼育", 105901, 11, "伊藤美来", "主を慕う、小さなガイド役", "エルフ", "コッコロ");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "A", 39, 9, 1, 2, "なに、モタモタしてんのよ\n仕方ないから、あたしが手伝ってあげるわ\nいい？　感謝しなさいよね！", "美食殿", 152, "猫と遊ぶ", 106001, 14, "立花理香", "行き倒れの謎のネコミミ魔法使い", "獣人族", "キャル");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "O", 40, 8, "", 11, "いいんだ、アタシは……独りでも。大丈夫だから、もう慣れたからさぁ", "？？？", 148, "冒険、思い出話", 106101, 16, "潘めぐみ", "さまよえる謎の少女", "ヒューマン", "ムイミ");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "O", 42, 6, "", 17, "", "？？？", 155, "キレイな葉っぱを集めること", 106301, 15, "優木かな", "森番を目指すエルフの少女", "エルフ", "アリサ");
