INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "O", "??", 3, "", 24, "", "？？？", 149, "物真似、芸術鑑賞", 107001, 24, "井口裕香", "研究所に隠れ住む物静かなお姉さん", "エルフ", "ネネカ");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "O", "??", 2, 8, 7, "", "王宮騎士団（NIGHTMARE）", 165, "強敵との闘争", 107101, 27, "たかはし智秋", "傍若無人な王宮騎士団副団長", "ヒューマン", "クリスティーナ");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "O", 46, 3, 1, 31, "あ、あの…何か食べ物持っていませんか？\nもう、お腹ペコペコで…", "美食殿", 156, "食べ歩き、料理", 107501, 17, "M・A・O", "いつも元気な腹ペコ少女", "ヒューマン", "ペコリーヌ（サマー）");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "B", 35, 5, 1, 11, "主さまのガイド役を仰せつかりました\nわたくし、主さまに満足していただけるよう\n誠心誠意尽くさせていただきます", "美食殿", 140, "瞑想、動植物の飼育", 107601, 11, "伊藤美来", "主を慕う、小さなガイド役", "エルフ", "コッコロ（サマー）");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "O", 43, 12, 9, 12, "うぅ…ごめんなさい～…\nまたキッチンを爆発させてしまいました～\nこれじゃあメイド失格です…", "サレンディア救護院", 154, "ご奉仕", 107701, 15, "悠木碧", "お嬢さまのためにがんばるドジっ娘メイド", "ヒューマン", "スズメ（サマー）");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "A", 39, 9, 1, 2, "なに、モタモタしてんのよ\n仕方ないから、あたしが手伝ってあげるわ\nいい？　感謝しなさいよね！", "美食殿", 152, "猫と遊ぶ", 107801, 14, "立花理香", "行き倒れの謎のネコミミ魔法使い", "獣人族", "キャル（サマー）");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "AB", 48, 3, 12, 1, "お金もうけの話なら、ぜひともあたしに\n持ってくるにゃ！　稼げるなら１ルピだって\n見逃さないのが、あたしの信条にゃ～♪", "メルクリウス財団", 158, "猫とたわむれること", 107901, 19, "沼倉愛美", "弱きを助け強きをくじく猫娘", "獣人族", "タマキ（サマー）");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "O", 49, 11, 12, 11, "私がキミの師匠になってあげる！\nもちろんタダとはいかないわ\n時給はしっかりもらうから", "メルクリウス財団", 163, "傭兵などのアルバイト", 108001, 20, "田所あずさ", "仕事も私事も効率優先な傭兵少女", "ヒューマン", "ミフユ（サマー）");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "AB", 42, 12, 7, 22, "私、小さい頃から人には見えないものが\n見えていたんです。今もあなたの後ろに\n一人、二人、三人…賑やかですね", "悪魔偽王国軍（ディアボロス）", 157, "占い", 108101, 18, "大坪由佳", "占いが得意な霊能少女", "魔族", "シノブ（ハロウィン）");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "B", 32, 1, 7, 23, "難しいことはわからないの～\nただ毎日プリンを食べられるなら、\n幽霊のままでいいの～", "悪魔偽王国軍（ディアボロス）", 130, "プリンを食べること", 108201, 14, "雨宮天", "プリン大好きゴースト娘", "魔族", "ミヤコ（ハロウィン）");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "A", 22, 1, 14, 3, "アタシのこと呼んだ？\nレディの魅力で夢中にさせてあげるわね！", "ルーセント学院", 120, "ファッション誌鑑賞、コスメ集め", 108301, 11, "久野美咲", "ちょっとおませな恋に恋する女の子", "魔族", "ミサキ（ハロウィン）");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "O", 46, 6, 4, 3, "私は人々の平和を守るため、唱喚術を使って\n戦います。…最近は、ア、アイドルとしても\n活動してますが、そちらはまだ不慣れで…", "カルミナ", 163, "各種楽器", 108401, 17, "福原綾香", "人々を守るために歌う、唱喚士の少女", "ヒューマン", "チカ（クリスマス）");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "B", 40, 6, 9, 9, "あの、えっと…私、く、クルミですぅ…\nふ、ふぇぇぇ…ど、どうしようぅ…\nは、恥かしくて…ご、ごめんなさいぃぃ！", "サレンディア救護院", 150, "観劇、おままごと", 108501, 12, "植田佳奈", "泣き虫で臆病な守ってあげたい女の子", "ヒューマン", "クルミ（クリスマス）");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "B", 38, 5, 9, 10, "この子はね、ぷうきちって言うんだ\n武器なんだけど、しゃべるんだよ♪\n大事な大事な、私の友達なんだぁ～！", "サレンディア救護院", 148, "屋内でできる遊び", 108601, 14, "芹澤優", "ぷうきちといつも一緒！", "ヒューマン", "アヤネ（クリスマス）");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "A", 44, 8, 2, 27, "こんにちは！　ヒヨリでっす！\n困っている人がいたら助けにいくよ！\nよかったら一緒に来ない？", "トゥインクルウィッシュ", 155, "人助け、応援", 108701, 16, "東山奈央", "人助けが大好き！　前向き格闘娘", "獣人族", "ヒヨリ（ニューイヤー）");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "O", 47, 4, 2, 5, "あんまり役に立てるかはわからないけど…\nわたしも頑張って、\nみんなをサポートするね！", "トゥインクルウィッシュ", 158, "料理、人間観察", 108801, 17, "種田梨沙", "戦闘のサポートが得意な、心優しい少女", "ヒューマン", "ユイ（ニューイヤー）");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "B", 46, 1, 2, 12, "キミと会ったのもきっと何かの縁だ\n一緒に塔の頂上を目指す仲間として\n頑張っていこう。よろしく頼む", "トゥインクルウィッシュ", 163, "読書、乗馬、お茶", 108901, 18, "早見沙織", "クールで何事にも真っ直ぐな剣士", "魔族", "レイ（ニューイヤー）");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "B", 43, 7, 13, 30, "『壊し屋』の二つ名を持つ私…\nですが、怖がる必要はありませんわ\nあなた様は大切な運命の人ですから…", "トワイライトキャラバン", 154, "実験、裁縫、料理", 109001, 16, "橋本ちなみ", "運命の相手に一途すぎる乙女", "魔族", "エリコ（バレンタイン）");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "O", 54, 10, 3, 24, "身の回りのお世話はお姉ちゃんがやってあげるね！\nお料理も、お洗濯も、お掃除も\nお風呂で背中も流してあげちゃうぞっ！", "ラビリンス", 168, "家事全般", 109101, 18, "生天目仁美", "お姉ちゃんがお世話してあげるからねっ！", "ヒューマン", "シズル（バレンタイン）");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "AB", 55, 12, "", 1, "私はアン！一応、マナリア王国の\n第一王女だけど…あまりかしこまらないで、\n気軽に仲良くしてくれたら嬉しいな！", "？？？", 156, "読書", 109201, 17, "日笠陽子", "英霊と契約を結んだマナリアの天才王女", "ヒューマン", "アン");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "O", 45, 2, "", 4, "ルゥはルゥですぅ！マナリア魔法学院に\n通ってるですぅ。あなたもルゥの\nお友だちになってくれるですか？", "？？？", 144, "食べること、眠ること", 109301, 16, "こやまきみこ", "マナリア魔法学院の新入生", "ヒューマン", "ルゥ");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "B", 67, 11, "", 3, "私はグレア。竜と人、両方の血を\n受け継いでいるの…\nえっと…よ、よろしくね", "？？？", 167, "ピアノ", 109401, 17, "福原綾香", "人を超越した力を有す心優しい竜姫", "半人半竜", "グレア");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "AB", 49, 11, 15, 19, "あなたのことを考えていました\n…逆らえないクウカをああして、こうして\nぐふ、ぐふふふ…", "ヴァイスフリューゲル　ランドソル支部", 157, "小説を読むこと", 109501, 18, "長妻樹里", "妄想大好き！　ほんとは照れ屋な女の子", "ヒューマン", "クウカ（オーエド）");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "O", 51, 8, 15, 31, "スシ、ゲイシャ、テンプラ…\nはふぅ～！\nトーゴクの文化はステキデスね～！", "ヴァイスフリューゲル　ランドソル支部", 163, "忍法開発", 109601, 16, "佐藤聡美", "トーゴクの神秘、オシエテクダサイ！", "ヒューマン", "ニノン（オーエド）");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "?", "??", 2, "", 2, "", "？？？", 154, "演劇鑑賞、詩文", 109701, 17, "水瀬いのり", "鬼がかりの万能妹メイド", "鬼族", "レム");
