INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "B", 52, 8, 14, 14, "いつも助けてくれてありがとう\n私のほうが年上なのに\n頼ってばかりでごめんなさい～", "ルーセント学院", 162, "恋愛小説、恋愛舞台、恋愛漫画の鑑賞", 110101, 23, "伊藤静", "多くの男性を魅了する無垢な女教師", "魔族", "イオ（サマー）");
