INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "A", 53, 7, 10, 7, "ハイターイ！　歌って踊って、\n最高に盛り上がるさ～！\nやさやさ、キミも一緒に踊るさ～！", "自警団（カォン）", 158, "踊り、空手", 110501, 17, "高森奈津美", "いつでも「なんくるないさ～」な天然娘", "獣人族", "カオリ（サマー）");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "O", 42, 9, 10, 22, "マホマホ王国のお姫はんの、マホ姫どす！\nけったいな顔してどないしはったん？\nマホマホ王国はずーっと遠くの国なんどす？", "自警団（カォン）", 155, "空想、ぬいぐるみ集め", 110601, 16, "内田真礼", "マホマホ王国のプリンセス", "獣人族", "マホ（サマー）");
