INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "B", 35, 5, 1, 11, "主さまのガイド役を仰せつかりました\nわたくし、主さまに満足していただけるよう\n誠心誠意尽くさせていただきます", "美食殿", 140, "瞑想、動植物の飼育", 111901, 11, "伊藤美来", "主を慕う、小さなガイド役", "エルフ", "コッコロ（ニューイヤー）");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "A", 39, 9, 1, 2, "なに、モタモタしてんのよ\n仕方ないから、あたしが手伝ってあげるわ\nいい？　感謝しなさいよね！", "美食殿", 152, "猫と遊ぶ", 112001, 14, "立花理香", "行き倒れの謎のネコミミ魔法使い", "獣人族", "キャル（ニューイヤー）");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "O", 43, 12, 9, 12, "うぅ…ごめんなさい～…\nまたキッチンを爆発させてしまいました～\nこれじゃあメイド失格です…", "サレンディア救護院", 154, "ご奉仕", 112101, 15, "悠木碧", "お嬢さまのためにがんばるドジっ娘メイド", "ヒューマン", "スズメ（ニューイヤー）");
