INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "A", 40, 11, 11, 3, "ゴホッ、ゴホッ…か、身体は弱いけど、\nせめて気持ちだけでも前向きに…！\nあっ、でもダメ…立ちくらみが…", "牧場（エリザベスパーク）", 153, "読書、お散歩", 112301, 14, "小清水亜美", "読書が趣味の病弱少女", "獣人族", "シオリ（マジカル）");
