INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "B", 35, 3, 11, 3, "オラはどんな時でもみんなに笑顔を届ける\n最高の芸人目指してる！\n一緒に頑張るべ！", "牧場（エリザベスパーク）", 142, "漫才", 112801, 20, "新田恵海", "みんなを笑顔にするお笑い牧場主", "ヒューマン", "マヒル（レンジャー）");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "A", 44, 8, 3, 25, "覚えていないと思うんですけど…\n私は妹なんですよ！\nだからお兄ちゃんって呼んでいいですか？", "ラビリンス", 156, "お裁縫", 112901, 15, "阿澄佳奈", "人懐っこくてマシンガントークな妹系少女", "ヒューマン", "リノ（ワンダー）");
