INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "A", 45, 7, 13, 5, "いいか、絶対に私を真名で呼ぶなよ？\n常に「機関」の眼や耳の存在を疑え\nそれが、生きのびるための術だ…！", "トワイライトキャラバン", 159, "小説執筆", 113201, 17, "髙野麻美", "前世を信じる中二病患者、「疾風の冥姫」", "魔族", "アンナ（サマー）");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "O", 55, 8, 13, 21, "", "トワイライトキャラバン", 166, "読書、魔法", 113301, 18, "佳村はるか", "オタク全開な魔法少女", "魔族", "ナナカ（サマー）");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "A", 46, 12, 6, 24, "私はハツネ！　困っている人の味方だよ！\n困った時は、いつでも言ってね♪\n私のちょ…ま、魔法で助けてあげるから！", "フォレスティエ", 156, "妹と遊ぶこと、二度寝、昼寝、早寝", 113401, 17, "大橋彩香", "みんなのために超能力を使う眠り姫", "エルフ", "ハツネ（サマー）");
