INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "A", 50, 10, 8, 25, "", "王宮騎士団（NIGHTMARE）", 171, "格闘技、湯浴み", 113601, 25, "川澄綾子", "素顔を見せない冷静沈着な女性騎士", "ヒューマン", "ジュン（サマー）");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "O", 42, 11, 7, 22, "アカリ、まだわからないことが多くて…\nだからこれから\nいろいろ教えてくださいね、お兄ちゃん！", "悪魔偽王国軍（ディアボロス）", 150, "サックス", 113701, 13, "浅倉杏美", "甘え上手なみんなの人気者", "魔族", "アカリ（エンジェル）");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "O", 40, 11, 7, 22, "え、えっと…こ、こういうときって、\nどういうことを言えばいいんだっけ…\nうう、どうしてちゃんと喋れないの…", "悪魔偽王国軍（ディアボロス）", 150, "ゲーム全般", 113801, 13, "原紗友里", "人見知りであまのじゃくな女の子", "魔族", "ヨリ（エンジェル）");
