INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "B", 46, 1, 2, 12, "キミと会ったのもきっと何かの縁だ\n一緒に塔の頂上を目指す仲間として\n頑張っていこう。よろしく頼む", "トゥインクルウィッシュ", 163, "読書、乗馬、お茶", 114001, 18, "早見沙織", "クールで何事にも真っ直ぐな剣士", "魔族", "レイ（ハロウィン）");
