INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "A", 33, 7, 15, 28, "「白き翼」こと、ヴァイスフリューゲル…\nその名に恥じぬよう、天高く舞い、\n華麗に敵を倒してみせる！", "ヴァイスフリューゲル　ランドソル支部", 140, "お菓子屋通い", 114201, 17, "辻あゆみ", "見た目も中身もお子ちゃまな異国の軍人", "ヒューマン", "モニカ（マジカル）");
