INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "A", 43, 10, 9, 4, "貧乏性？　いいえ、\n「もったいない」の精神で\n日々を過ごしてるだけよ！", "サレンディア救護院", 156, "経営、お茶会", 114501, 17, "堀江由衣", "救護院を経営する優しい庶民派お嬢様", "エルフ", "サレン（クリスマス）");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "A", 55, 3, 12, 16, "キミには情けないところばかり\n見られているけど、こんなところ、\nキミ以外には見せないんだからね？", "メルクリウス財団", 164, "ウインドーショッピング", 114601, 22, "今井麻美", "純情でほっとけない大人の女性", "エルフ", "ユカリ（クリスマス）");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "O", 40, 8, "", 11, "いいんだ、アタシは……独りでも。大丈夫だから、もう慣れたからさぁ", "？？？", 148, "冒険、思い出話", 114701, 16, "潘めぐみ", "さまよえる謎の少女", "ヒューマン", "ムイミ（ニューイヤー）");
