INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "B", 35, 5, 1, 11, "主さまのガイド役を仰せつかりました\nわたくし、主さまに満足していただけるよう\n誠心誠意尽くさせていただきます", "美食殿", 140, "瞑想、動植物の飼育", 115501, 11, "伊藤美来", "主を慕う、小さなガイド役", "エルフ", "コッコロ（儀装束）");
