INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "A", 100, 3, 11, 14, "私、ごく普通の、どこにでもいる女の子よ！\nみ、見た目以外はね…", "牧場（エリザベスパーク）", 150, "毛繕い、お喋り", 115801, 17, "徳井青空", "乙女チックなもふもふアニマル", "獣人族", "リマ（シンデレラ）");
