INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "O", 42, 9, 10, 22, "マホマホ王国のお姫はんの、マホ姫どす！\nけったいな顔してどないしはったん？\nマホマホ王国はずーっと遠くの国なんどす？", "自警団（カォン）", 155, "空想、ぬいぐるみ集め", 116001, 16, "内田真礼", "マホマホ王国のプリンセス", "獣人族", "マホ（シンデレラ）");
