INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "AB", 48, 3, 12, 1, "お金もうけの話なら、ぜひともあたしに\n持ってくるにゃ！　稼げるなら１ルピだって\n見逃さないのが、あたしの信条にゃ～♪", "メルクリウス財団", 158, "猫とたわむれること", 116801, 19, "沼倉愛美", "弱きを助け強きをくじく猫娘", "獣人族", "タマキ（作業服）");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "O", 49, 11, 12, 11, "私がキミの師匠になってあげる！\nもちろんタダとはいかないわ\n時給はしっかりもらうから", "メルクリウス財団", 163, "傭兵などのアルバイト", 116901, 20, "田所あずさ", "仕事も私事も効率優先な傭兵少女", "ヒューマン", "ミフユ（作業服）");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "B", 43, 7, 13, 30, "『壊し屋』の二つ名を持つ私…\nですが、怖がる必要はありませんわ\nあなた様は大切な運命の人ですから…", "トワイライトキャラバン", 154, "実験、裁縫、料理", 117001, 16, "橋本ちなみ", "運命の相手に一途すぎる乙女", "魔族", "エリコ（サマー）");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "O", 54, 10, 3, 24, "身の回りのお世話はお姉ちゃんがやってあげるね！\nお料理も、お洗濯も、お掃除も\nお風呂で背中も流してあげちゃうぞっ！", "ラビリンス", 168, "家事全般", 117101, 18, "生天目仁美", "お姉ちゃんがお世話してあげるからねっ！", "ヒューマン", "シズル（サマー）");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "B", 40, 1, 4, 24, "", "カルミナ", 157, "舞台鑑賞、ダンス", 117201, 17, "日笠陽子", "歌って踊れる大人気アイドル", "ヒューマン", "ノゾミ（サマー）");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "O", 46, 6, 4, 3, "私は人々の平和を守るため、唱喚術を使って\n戦います。…最近は、ア、アイドルとしても\n活動してますが、そちらはまだ不慣れで…", "カルミナ", 163, "各種楽器", 117301, 17, "福原綾香", "人々を守るために歌う、唱喚士の少女", "ヒューマン", "チカ（サマー）");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "AB", 45, 9, 4, 7, "", "カルミナ", 153, "裁縫", 117401, 14, "木戸衣吹", "ファッション大好きなキュートガール", "ヒューマン", "ツムギ（サマー）");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "A", 53, 3, 13, 7, "私は科学者だけど、\n医者の真似事もしてるの\n病気になったら診てあげるわ", "トワイライトキャラバン", 166, "研究、実験", 117501, 27, "三石琴乃", "実験が趣味の危険な科学者", "ヒューマン", "ミツキ（オーエド）");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "AB", 40, 10, 15, 10, "ボクって本当に美しいなあ…\n可愛くて美しいなんて本当に罪だと思うけど\n生まれもったものだから仕方ないんだ♪", "ヴァイスフリューゲル　ランドソル支部", 150, "鏡で自分を見ること", 117601, 14, "大空直美", "ボクは誰よりも美しい", "エルフ", "ユキ（オーエド）");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "A", 53, 7, 10, 7, "ハイターイ！　歌って踊って、\n最高に盛り上がるさ～！\nやさやさ、キミも一緒に踊るさ～！", "自警団（カォン）", 158, "踊り、空手", 117701, 17, "高森奈津美", "いつでも「なんくるないさ～」な天然娘", "獣人族", "カオリ（ハロウィン）");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "O", 51, 8, 15, 31, "スシ、ゲイシャ、テンプラ…\nはふぅ～！\nトーゴクの文化はステキデスね～！", "ヴァイスフリューゲル　ランドソル支部", 163, "忍法開発", 117801, 16, "佐藤聡美", "トーゴクの神秘、オシエテクダサイ！", "ヒューマン", "ニノン（ハロウィン）");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "O", 48, 4, 14, 10, "ヒデサイ、ちょっす～！　うち、漢字と計算は\nちょっち…てか、おに苦手なんだ～\nでもでも、ファッションだったら任せて～！", "ルーセント学院", 167, "ファッション", 117901, 17, "上坂すみれ", "天真爛漫で人気者のカリスマモデル", "魔族", "スズナ（ハロウィン）");
