INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "AB", 49, 11, 15, 19, "あなたのことを考えていました\n…逆らえないクウカをああして、こうして\nぐふ、ぐふふふ…", "ヴァイスフリューゲル　ランドソル支部", 157, "小説を読むこと", 119101, 18, "長妻樹里", "妄想大好き！　ほんとは照れ屋な女の子", "ヒューマン", "クウカ（ノワール）");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "B", 35, 3, 11, 3, "オラはどんな時でもみんなに笑顔を届ける\n最高の芸人目指してる！\n一緒に頑張るべ！", "牧場（エリザベスパーク）", 142, "漫才", 119201, 20, "新田恵海", "みんなを笑顔にするお笑い牧場主", "ヒューマン", "マヒル（クリスマス）");
