INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "A", 22, 1, 14, 3, "アタシのこと呼んだ？\nレディの魅力で夢中にさせてあげるわね！", "ルーセント学院", 120, "ファッション誌鑑賞、コスメ集め", 121401, 11, "久野美咲", "ちょっとおませな恋に恋する女の子", "魔族", "ミサキ（ステージ）");
