INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "AB", "???", 9, 17, 29, "", "ドラゴンズネスト", 145, "ゲーム", 121601, 13, "藤田茜", "口が達者なヘタレドラゴン", "ドラゴン族", "イノリ（怪盗）");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "A", 45, 7, 13, 5, "いいか、絶対に私を真名で呼ぶなよ？\n常に「機関」の眼や耳の存在を疑え\nそれが、生きのびるための術だ…！", "トワイライトキャラバン", 159, "小説執筆", 121901, 17, "髙野麻美", "前世を信じる中二病患者、「疾風の冥姫」", "魔族", "アンナ（パイレーツ）");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "AB", 42, 12, 7, 22, "私、小さい頃から人には見えないものが\n見えていたんです。今もあなたの後ろに\n一人、二人、三人…賑やかですね", "悪魔偽王国軍（ディアボロス）", 157, "占い", 122001, 18, "大坪由佳", "占いが得意な霊能少女", "魔族", "シノブ（パイレーツ）");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "AB", 44, 6, 6, 6, "", "フォレスティエ", 158, "友達作りのイメトレ", 122101, 13, "花澤香菜", "「友達」に憧れる、エルフの森の女の子", "エルフ", "アオイ（キャンプ）");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "A", 55, 3, 12, 16, "キミには情けないところばかり\n見られているけど、こんなところ、\nキミ以外には見せないんだからね？", "メルクリウス財団", 164, "ウインドーショッピング", 122201, 22, "今井麻美", "純情でほっとけない大人の女性", "エルフ", "ユカリ（キャンプ）");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "AB", 41, 12, "", 6, "", "？？？", 149, "お散歩、お料理", 122301, "??", "釘宮理恵", "けんぞくのご主人様", "魔族", "ヴァンピィ");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "A", 44, 8, 2, 27, "こんにちは！　ヒヨリでっす！\n困っている人がいたら助けにいくよ！\nよかったら一緒に来ない？", "トゥインクルウィッシュ", 155, "人助け、応援", 122401, 16, "東山奈央", "人助けが大好き！　前向き格闘娘", "獣人族", "ヒヨリ（サマー）");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "B", 46, 1, 2, 12, "キミと会ったのもきっと何かの縁だ\n一緒に塔の頂上を目指す仲間として\n頑張っていこう。よろしく頼む", "トゥインクルウィッシュ", 163, "読書、乗馬、お茶", 122501, 18, "早見沙織", "クールで何事にも真っ直ぐな剣士", "魔族", "レイ（サマー）");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "O", 47, 4, 2, 5, "あんまり役に立てるかはわからないけど…\nわたしも頑張って、\nみんなをサポートするね！", "トゥインクルウィッシュ", 158, "料理、人間観察", 122601, 17, "種田梨沙", "戦闘のサポートが得意な、心優しい少女", "ヒューマン", "ユイ（サマー）");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "A", 21, 2, 5, 2, "", "リトルリリカル", 118, "お勉強", 122701, 8, "小倉唯", "礼儀正しくしっかり者のちびっ子優等生", "エルフ", "キョウカ（サマー）");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "O", 27, 8, 5, 10, "イタズラなら任せて！\nにいちゃん、引っかからないように気を付けなよー♪", "リトルリリカル", 128, "いたずら、探検", 122801, 9, "諸星すみれ", "探検好きのイタズラっ子", "ヒューマン", "ミソギ（サマー）");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "O", 21, 4, 5, 3, "ぴょんぴょん、うさぎさんになりたいな～♪　\nミミ、うさぎさんになれたら、\n最初におにいちゃんに見せてあげるね！", "リトルリリカル", 117, "かわいいもの集め", 122901, 10, "日高里菜", "お歌もにんじんも、ウサギさんも大好き♪", "獣人族", "ミミ（サマー）");
