INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "O", 42, 9, 10, 22, "マホマホ王国のお姫はんの、マホ姫どす！\nけったいな顔してどないしはったん？\nマホマホ王国はずーっと遠くの国なんどす？", "自警団（カォン）", 155, "空想、ぬいぐるみ集め", 123101, 16, "内田真礼", "マホマホ王国のプリンセス", "獣人族", "マホ（エクスプローラー）");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "B", 38, 5, 9, 10, "この子はね、ぷうきちって言うんだ\n武器なんだけど、しゃべるんだよ♪\n大事な大事な、私の友達なんだぁ～！", "サレンディア救護院", 148, "屋内でできる遊び", 123201, 14, "芹澤優", "ぷうきちといつも一緒！", "ヒューマン", "アヤネ（エクスプローラー）");
