INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "O", 42, 11, 7, 22, "アカリ、まだわからないことが多くて…\nだからこれから\nいろいろ教えてくださいね、お兄ちゃん！", "悪魔偽王国軍（ディアボロス）", 150, "サックス", 124001, 13, "浅倉杏美", "甘え上手なみんなの人気者", "魔族", "アカリ（クリスマス）");
