INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "AB", 48, 3, 12, 1, "お金もうけの話なら、ぜひともあたしに\n持ってくるにゃ！　稼げるなら１ルピだって\n見逃さないのが、あたしの信条にゃ～♪", "メルクリウス財団", 158, "猫とたわむれること", 125101, 19, "沼倉愛美", "弱きを助け強きをくじく猫娘", "獣人族", "タマキ（カフェ）");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "A", 33, 7, 15, 28, "「白き翼」こと、ヴァイスフリューゲル…\nその名に恥じぬよう、天高く舞い、\n華麗に敵を倒してみせる！", "ヴァイスフリューゲル　ランドソル支部", 140, "お菓子屋通い", 125201, 17, "辻あゆみ", "見た目も中身もお子ちゃまな異国の軍人", "ヒューマン", "モニカ（カフェ）");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "B", 35, 5, 1, 11, "主さまのガイド役を仰せつかりました\nわたくし、主さまに満足していただけるよう\n誠心誠意尽くさせていただきます", "美食殿", 140, "瞑想、動植物の飼育", 125301, 11, "伊藤美来", "主を慕う、小さなガイド役", "エルフ", "コッコロ（レンジャー）");
INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "A", 40, 11, 11, 3, "ゴホッ、ゴホッ…か、身体は弱いけど、\nせめて気持ちだけでも前向きに…！\nあっ、でもダメ…立ちくらみが…", "牧場（エリザベスパーク）", 153, "読書、お散歩", 125401, 14, "小清水亜美", "読書が趣味の病弱少女", "獣人族", "シオリ（レンジャー）");
