INSERT INTO `v1_8234d10af234ff318d38ac1aa8f42ec39cf8101fde2a5f4a0faa6218ee99ca93` VALUES (0, "A", 55, 3, 12, 16, "キミには情けないところばかり\n見られているけど、こんなところ、\nキミ以外には見せないんだからね？", "メルクリウス財団", 164, "ウインドーショッピング", 126801, 22, "今井麻美", "純情でほっとけない大人の女性", "エルフ", "ユカリ（サマー）");
